class BatchTransactionHandler {
  constructor(ethereumService) {
    this.ethService = ethereumService;
  }

  /**
   * Send multiple ETH transactions in sequence with proper nonce management
   * @param {Array} transactions - Array of {to, amount} objects
   * @returns {Array} Array of transaction receipts
   */
  async sendBatchEth(transactions) {
    const results = [];
    let nonce = await this.ethService.getNonce();

    for (const tx of transactions) {
      try {
        const result = await this.ethService.sendEth(tx.to, tx.amount, { nonce });
        results.push({ ...result, originalTx: tx });
        nonce++;
      } catch (error) {
        results.push({
          status: 'error',
          error: error.message,
          originalTx: tx,
        });
        // Continue with next transaction, increment nonce if tx was sent
        if (error.message.includes('already known')) {
          nonce++;
        }
      }
    }

    return results;
  }

  /**
   * Send multiple token transfers in sequence
   * @param {string} tokenAddress - Token contract address
   * @param {Array} transfers - Array of {to, amount} objects
   * @returns {Array} Array of transaction receipts
   */
  async sendBatchTokenTransfers(tokenAddress, transfers) {
    const results = [];
    let nonce = await this.ethService.getNonce();

    for (const transfer of transfers) {
      try {
        const result = await this.ethService.transferToken(
          tokenAddress,
          transfer.to,
          transfer.amount,
          { nonce }
        );
        results.push({ ...result, originalTransfer: transfer });
        nonce++;
      } catch (error) {
        results.push({
          status: 'error',
          error: error.message,
          originalTransfer: transfer,
        });
        if (error.message.includes('already known')) {
          nonce++;
        }
      }
    }

    return results;
  }
}

